#include <cstdio>
#include <cstdlib>
#include <omp.h>

// Example kernel function translated from OpenCL to OpenMP
void example_kernel(float* data, int size) {
    #pragma omp parallel for
    for(int i = 0; i < size; i++) {
        data[i] = data[i] * data[i]; // Example computation
    }
}

int main(int argc, char** argv) {
    const int N = 1024 * 1024;
    float* data = (float*)malloc(sizeof(float) * N);
    if (!data) {
        fprintf(stderr, "Failed to allocate memory\n");
        return -1;
    }

    // Initialize data
    for (int i = 0; i < N; i++) {
        data[i] = (float)i;
    }

    // Run kernel
    example_kernel(data, N);

    // Print some results
    for (int i = 0; i < 10; i++) {
        printf("data[%d] = %f\n", i, data[i]);
    }

    free(data);
    return 0;
}
